<?php namespace App\Repositories\Fee;use App\Repositories\BaseRepository;use App\Models\Fee\Scholarship;use Illuminate\Database\Eloquent\Collection;class ScholarshipRepository extends BaseRepository{    public function __construct(Scholarship $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByCode(string $code): ?Scholarship    {        return $this->query()->where('code', $code)->first();    }    public function findByName(string $name): ?Scholarship    {        return $this->query()->where('name', $name)->first();    }    public function getActiveScholarships(): Collection    {        return $this->query()->where('is_active', true)->where(function ($q) {                $q->whereNull('valid_until')->orWhere('valid_until', '>=', now());            })->get();    }    public function getByType(string $type): Collection    {        return $this->findByField('type', $type);    }    public function getBySponsor(string $sponsor): Collection    {        return $this->findByField('sponsor', $sponsor);    }    public function searchScholarships(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('code', 'like', "%{$keyword}%")->orWhere('sponsor', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }    public function getByEligibleClass(int $classId): Collection    {        return $this->query()->where(function ($q) use ($classId) {                $q->whereRaw("FIND_IN_SET(?, eligible_classes)", [$classId])->orWhereNull('eligible_classes');            })->get();    }    public function getStudentsByScholarship(int $scholarshipId): Collection    {        return $this->query()->with('students')->findOrFail($scholarshipId);    }}